:root {
  --card-bg: #ffffff;
  --header-bg: #c0392b;
  --header-text: #ffffff;
  --tag-bg: #e8c4c0;
  --tag-text: #7d1a12;
  --title-text: #ffffff;
  --subtitle-text: #f5cbc7;
  --meta-bg: #fdf6f5;
  --meta-border: #f0d5d2;
  --meta-value-text: #c0392b;
  --meta-label-text: #a0857f;
  --divider-color: #e8ccc9;
  --ingredients-bg: #fff9f9;
  --ingredients-border: #f0d5d2;
  --ingredients-title: #5c2e2a;
  --ingredient-bg: #fdecea;
  --ingredient-text: #9b2c1f;
  --ingredient-border: #f5c6c0;
  --btn-bg: #c0392b;
  --btn-text: #ffffff;
  --btn-hover-bg: #a93226;
  --card-radius: 16px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.recipe-card {
  background: var(--card-bg);
  border-radius: var(--card-radius);
  width: 300px;
  overflow: hidden;
  border: 1px solid var(--meta-border);
}

.recipe-header {
  background: var(--header-bg);
  padding: 22px 20px 18px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.cuisine-tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  padding: 3px 10px;
  border-radius: 20px;
  align-self: flex-start;
}

.recipe-title {
  color: var(--title-text);
  font-size: 20px;
  font-weight: 800;
  margin: 0;
  line-height: 1.2;
}

.recipe-subtitle {
  color: var(--subtitle-text);
  font-size: 13px;
  font-weight: 400;
  margin: 0;
  line-height: 1.4;
}

.recipe-meta {
  background: var(--meta-bg);
  border-bottom: 1px solid var(--meta-border);
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding: 14px 16px;
}

.meta-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.meta-value {
  color: var(--meta-value-text);
  font-size: 20px;
  font-weight: 800;
  line-height: 1;
}

.meta-label {
  color: var(--meta-label-text);
  font-size: 11px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.meta-divider {
  width: 1px;
  height: 32px;
  background: var(--divider-color);
}

.ingredients {
  background: var(--ingredients-bg);
  padding: 14px 16px;
  border-bottom: 1px solid var(--ingredients-border);
}

.ingredients-title {
  color: var(--ingredients-title);
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  margin: 0 0 10px 0;
}

.ingredient-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.ingredient {
  background: var(--ingredient-bg);
  color: var(--ingredient-text);
  border: 1px solid var(--ingredient-border);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 6px;
}

.view-btn {
  display: block;
  width: 100%;
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  padding: 14px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  letter-spacing: 0.03em;
}
